// Live-Wetter ueber open-meteo (gratis). Verkettet Geocoding + Wetter-Abruf.
// Eingabe: { stadt: string }
async function run(input) {
  const stadt = String((input && input.stadt) || 'Basel');
  const geo = await (await fetch('https://geocoding-api.open-meteo.com/v1/search?count=1&name=' + encodeURIComponent(stadt))).json();
  if (!geo.results || !geo.results[0]) return { fehler: 'Ort nicht gefunden' };
  const g = geo.results[0];
  const w = await (await fetch('https://api.open-meteo.com/v1/forecast?current=temperature_2m,wind_speed_10m,weather_code&latitude=' + g.latitude + '&longitude=' + g.longitude)).json();
  const c = w.current || {};
  return { ort: g.name, land: g.country, temperaturC: c.temperature_2m, windKmh: c.wind_speed_10m, wettercode: c.weather_code };
}
